module ring_counter (
    input wire reset_clk,
    input wire rst,
    output reg [3:0] count
);

    always @(posedge reset_clk or posedge rst) begin
        if (rst) begin
            count <= 4'b0001;
        end else begin
            count <= {count[2:0], count[3]};
        end
    end

endmodule
